import React from 'react';
import { Card, CardContent, Box, Typography, Stack, Chip } from '@mui/material';
import response from './response.json';

interface Arrival {
  line: string;
  destination: string;
  scheduledTime: string;
  realTimeDelay: string;
}

export default function Widget() {
  const widgetData = response.data;
  const { station, upcomingArrivals } = widgetData.data;
  const meta = widgetData.meta;

  return (
    <Card sx={{ width: 'fit-content', minWidth: 320, maxWidth: 450, bgcolor: '#303030', color: '#FFFFFF' }} elevation={2}>
      <CardContent sx={{ p: 2.5 }}>
        <Stack spacing={2}>
          <Box>
            <Typography variant="h6" sx={{ mb: 1 }}>
              {widgetData.widget.app}
            </Typography>
            <Typography variant="body2" color="text.secondary">
              Station: {station}
            </Typography>
          </Box>
          <Box>
            <Typography variant="body2" sx={{ mb: 1, color: meta.accentColor }}>
              Upcoming Arrivals
            </Typography>
            <Stack spacing={1}>
              {upcomingArrivals.map((arrival: Arrival, index: number) => (
                <Box key={index} sx={{ p: 1, bgcolor: '#424242', borderRadius: 1 }}>
                  <Stack direction="row" justifyContent="space-between" alignItems="center">
                    <Box>
                      <Typography variant="body2" sx={{ fontWeight: 500 }}>
                        {arrival.line}
                      </Typography>
                      <Typography variant="caption" color="text.secondary">
                        To {arrival.destination}
                      </Typography>
                    </Box>
                    <Box textAlign="right">
                      <Typography variant="body2" sx={{ fontWeight: 500 }}>
                        {arrival.scheduledTime}
                      </Typography>
                      <Typography variant="caption" sx={{ color: meta.primaryColor }}>
                        {arrival.realTimeDelay}
                      </Typography>
                    </Box>
                  </Stack>
                </Box>
              ))}
            </Stack>
          </Box>
        </Stack>
      </CardContent>
    </Card>
  );
}
